@media screen and (max-width: 749px) {

body,
#main-content {
  background: #f8f6f3 !important;
}

.product-layout {
  background: #fff !important;
  border-radius: 0 0 12px 12px !important;
  box-shadow: 0 3px 14px rgba(0,0,0,0.04) !important;
  margin-bottom: 20px !important;
  padding-bottom: 6px !important;
}

.product-info {
  padding: 0 18px !important;
}

.product-images {
  position: relative !important;
}

.product-images .badge,
.product-images [class*="badge"],
.product-images [class*="certified"] {
  position: absolute !important;
  top: 12px !important;
  left: 12px !important;
  z-index: 5 !important;
  background: #7a3045 !important;
  color: #fff !important;
  font-size: 10px !important;
  font-weight: 800 !important;
  padding: 5px 12px !important;
  border-radius: 4px !important;
  text-transform: uppercase !important;
  letter-spacing: 0.07em !important;
}

.product-thumbnails {
  display: flex !important;
  gap: 8px !important;
  padding: 8px 18px 12px !important;
  overflow-x: auto !important;
  -webkit-overflow-scrolling: touch !important;
  scrollbar-width: none !important;
}

.product-thumbnails::-webkit-scrollbar {
  display: none !important;
}

.product-thumbnails button {
  flex: 0 0 58px !important;
  height: 58px !important;
  border-radius: 6px !important;
  border: 2px solid #e4dfd6 !important;
  overflow: hidden !important;
  padding: 2px !important;
  background: #fff !important;
}

.product-thumbnails button.active,
.product-thumbnails button[aria-current="true"] {
  border-color: #7a3045 !important;
}

#product-price-main {
  font-size: 28px !important;
  font-weight: 800 !important;
  color: #1a1a1a !important;
  letter-spacing: -0.02em !important;
}

.product-price-wrap {
  margin: 8px 0 6px !important;
}

.product-persuasion-stack {
  margin: 16px 0 14px !important;
  padding: 0 !important;
  display: flex !important;
  flex-direction: column !important;
  gap: 0 !important;
  counter-reset: persuasion !important;
}

.persuasion-row {
  padding: 12px 0 12px 42px !important;
  border-bottom: 1px solid #ece7de !important;
  font-size: 13px !important;
  line-height: 1.5 !important;
  position: relative !important;
  background: transparent !important;
  counter-increment: persuasion !important;
}

.persuasion-row::before {
  content: counter(persuasion) !important;
  position: absolute !important;
  left: 0 !important;
  top: 10px !important;
  width: 28px !important;
  height: 28px !important;
  background: #7a3045 !important;
  color: #fff !important;
  border-radius: 50% !important;
  font-size: 12px !important;
  font-weight: 800 !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  line-height: 1 !important;
}

.persuasion-row:last-child {
  border-bottom: none !important;
}

.product-review-callout {
  background: #fff !important;
  border: 1px solid #e4dfd6 !important;
  border-bottom: 4px solid #7a3045 !important;
  border-radius: 8px !important;
  padding: 16px 16px 14px !important;
  margin: 16px 0 !important;
  font-size: 14px !important;
  line-height: 1.55 !important;
  color: #333 !important;
  box-shadow: 0 2px 8px rgba(0,0,0,0.03) !important;
}

.sealsubs-target-element {
  margin: 14px 0 10px !important;
}

.sls-option-container {
  border: 2px solid #e4dfd6 !important;
  border-radius: 8px !important;
  padding: 13px 14px !important;
  margin-bottom: 8px !important;
  transition: border-color 0.15s ease, background 0.15s ease !important;
}

.sls-option-container.sls-active {
  border-color: #7a3045 !important;
  background: #fdf7f8 !important;
}

.product-actions {
  position: sticky !important;
  bottom: 0 !important;
  z-index: 90 !important;
  background: #fff !important;
  padding: 10px 18px max(10px, env(safe-area-inset-bottom)) !important;
  margin: 0 -18px !important;
  box-shadow: 0 -1px 0 #e4dfd6, 0 -6px 18px rgba(0,0,0,0.06) !important;
}

.product-actions button[type="submit"],
.product-actions .add-to-cart,
.product-actions [class*="add-to-cart"] {
  background: #7a3045 !important;
  color: #fff !important;
  font-size: 15.5px !important;
  font-weight: 700 !important;
  padding: 16px 24px !important;
  border-radius: 8px !important;
  width: 100% !important;
  min-height: 54px !important;
  border: none !important;
  cursor: pointer !important;
  letter-spacing: 0.015em !important;
  box-shadow: 0 2px 8px rgba(122,48,69,0.25) !important;
}

.product-quantity {
  margin-bottom: 8px !important;
}

.quantity-selector {
  border: 1.5px solid #e4dfd6 !important;
  border-radius: 8px !important;
}

.quantity-selector button {
  min-width: 44px !important;
  min-height: 44px !important;
}

.guarantee-badge {
  border-top: 1px solid #7a3045 !important;
  border-bottom: 1px solid #7a3045 !important;
  border-left: none !important;
  border-right: none !important;
  border-radius: 0 !important;
  padding: 11px 16px !important;
  margin: 8px 0 4px !important;
  text-align: center !important;
  font-size: 12.5px !important;
  font-weight: 700 !important;
  color: #7a3045 !important;
  background: transparent !important;
  letter-spacing: 0.04em !important;
}

.product-description {
  padding: 14px 0 !important;
  font-size: 14px !important;
  line-height: 1.6 !important;
  color: #555 !important;
}

.product-story {
  background: #fff !important;
  border-radius: 12px !important;
  border: 1px solid #e4dfd6 !important;
  padding: 28px 20px 24px !important;
  margin: 0 14px 20px !important;
  text-align: center !important;
  box-shadow: 0 2px 12px rgba(0,0,0,0.04) !important;
  position: relative !important;
}

.product-story::before {
  content: "" !important;
  position: absolute !important;
  top: 0 !important;
  left: 50% !important;
  transform: translateX(-50%) !important;
  width: 48px !important;
  height: 4px !important;
  background: #7a3045 !important;
  border-radius: 0 0 4px 4px !important;
}

.story-content {
  font-size: 14.5px !important;
  line-height: 1.65 !important;
  color: #444 !important;
}

.story-content h2,
.story-content h3,
.product-story h2,
.product-story h3 {
  font-size: 19px !important;
  font-weight: 800 !important;
  color: #1a1a1a !important;
  margin-bottom: 10px !important;
}

.story-stats {
  display: grid !important;
  grid-template-columns: repeat(3, 1fr) !important;
  gap: 8px !important;
  margin-top: 20px !important;
}

.stat {
  background: #fdf7f8 !important;
  border: 1px solid rgba(122,48,69,0.12) !important;
  border-radius: 8px !important;
  padding: 14px 6px 10px !important;
  text-align: center !important;
  font-size: 9.5px !important;
  font-weight: 700 !important;
  text-transform: uppercase !important;
  letter-spacing: 0.06em !important;
  color: #888 !important;
  line-height: 1.35 !important;
}

.stat strong,
.stat b,
.stat .stat-number {
  display: block !important;
  font-size: 24px !important;
  font-weight: 800 !important;
  color: #7a3045 !important;
  margin-bottom: 3px !important;
  letter-spacing: -0.02em !important;
}

#product-reviews,
.hg-reviews-ready {
  background: #fff !important;
  border-radius: 12px !important;
  border: 1px solid #e4dfd6 !important;
  padding: 24px 16px 18px !important;
  margin: 0 14px 20px !important;
  box-shadow: 0 2px 12px rgba(0,0,0,0.04) !important;
}

.jdgm-rev-widg__header {
  text-align: center !important;
  padding-bottom: 16px !important;
  margin-bottom: 16px !important;
  border-bottom: 1px solid #ece7de !important;
}

.hg-review-item {
  padding: 14px 0 !important;
  border-bottom: 1px solid #ece7de !important;
}

.hg-review-item:last-child {
  border-bottom: none !important;
}

#hg-reviews-fallback button,
.hg-reviews-content button[class*="load"],
.hg-reviews-content [class*="Load"],
.hg-review-list + button,
.hg-review-list ~ button {
  width: 100% !important;
  padding: 13px !important;
  border: 2px solid #7a3045 !important;
  border-radius: 8px !important;
  background: transparent !important;
  color: #7a3045 !important;
  font-weight: 700 !important;
  font-size: 13px !important;
  cursor: pointer !important;
  margin-top: 12px !important;
}

}
